/**
 * Custom ESLint Plugin: No Product Imports in Shared
 *
 * Prevents product-specific imports inside `src/components/`.
 * Shared components must not depend on product modules, feature
 * directories, or product-specific auto-generated API hooks.
 * This ensures shared components remain reusable across all products.
 *
 * Banned import sources (when the importing file is under src/components/):
 *   - @baseclient/*-module (except identity-module, which is shared infra)
 *   - server/autoGeneratedHooks/{onlinemenu,questioner,content,notification}/
 *   - src/features/ or src/modules/
 *
 * Allowed:
 *   - @baseclient/core, @baseclient/identity-client (shared infra)
 *   - src/shared/, src/lib/, src/localization/, src/components/
 *   - External packages (react, react-native, etc.)
 *   - Relative imports within src/components/
 *
 * Examples:
 *   BAD:  import { X } from '@baseclient/onlinemenu-module';
 *   BAD:  import { Y } from '../../server/autoGeneratedHooks/questioner/...';
 *   BAD:  import type { Z } from '@baseclient/questioner-module';
 *   GOOD: import { A } from '@baseclient/core';
 *   GOOD: import { B } from '../../shared/utils';
 */

import { posix, sep } from 'path';

/**
 * Scoped @baseclient packages that are shared infrastructure
 * and allowed in src/components/.
 */
const ALLOWED_BASECLIENT_PACKAGES = new Set([
  '@baseclient/core',
  '@baseclient/identity-client',
  '@baseclient/identity-module',
]);

/**
 * Product-specific auto-generated hook directory names under
 * server/autoGeneratedHooks/ that are banned.
 */
const PRODUCT_HOOK_DIRS = new Set([
  'onlinemenu',
  'questioner',
  'content',
  'notification',
]);

/**
 * Normalize a file path to use forward slashes for consistent matching.
 */
function normalizePath(filePath) {
  return filePath.split(sep).join(posix.sep);
}

/**
 * Check whether a file path is inside src/components/.
 */
function isInsideSharedComponents(filePath) {
  const normalized = normalizePath(filePath);
  return normalized.includes('/src/components/');
}

/**
 * Check whether an import source is a banned @baseclient product module.
 * Bans any @baseclient/*-module package except those in the allow list.
 */
function isBannedBaseclientModule(source) {
  if (!source.startsWith('@baseclient/')) return false;
  if (ALLOWED_BASECLIENT_PACKAGES.has(source)) return false;
  return source.endsWith('-module');
}

/**
 * Check whether an import source resolves to a product-specific
 * auto-generated hooks directory.
 */
function isBannedAutoGeneratedHook(source) {
  const normalized = normalizePath(source);
  for (const dir of PRODUCT_HOOK_DIRS) {
    if (normalized.includes(`autoGeneratedHooks/${dir}`)) return true;
    if (normalized.includes(`autoGeneratedHooks/${dir}/`)) return true;
  }
  return false;
}

/**
 * Check whether an import source points to src/features/ or src/modules/.
 */
function isBannedFeatureOrModulePath(source) {
  const normalized = normalizePath(source);
  return (
    normalized.includes('/src/features/') ||
    normalized.includes('/src/modules/') ||
    normalized.includes('/features/') ||
    normalized.includes('/modules/')
  );
}

const noProductImportsInSharedRule = {
  meta: {
    type: 'problem',
    docs: {
      description:
        'Disallow product-specific imports in src/components/. ' +
        'Shared components must not depend on product modules.',
      category: 'Best Practices',
      recommended: true,
    },
    schema: [],
    messages: {
      productImportInShared:
        'Shared components in src/components/ must not import from ' +
        'product-specific modules ({{source}}). Move product-specific ' +
        'logic to the feature module, or extract shared types to ' +
        '@baseclient/core.',
    },
  },

  create(context) {
    const filePath = context.filename || context.getFilename();
    if (!filePath) return {};

    // Only apply to files inside src/components/
    if (!isInsideSharedComponents(filePath)) return {};

    /**
     * Check a single import/export declaration for banned sources.
     */
    function checkImportSource(node) {
      const source = node.source;
      if (!source) return;

      const importPath = source.value;
      if (typeof importPath !== 'string') return;

      const isBanned =
        isBannedBaseclientModule(importPath) ||
        isBannedAutoGeneratedHook(importPath) ||
        isBannedFeatureOrModulePath(importPath);

      if (isBanned)
        context.report({
          node,
          messageId: 'productImportInShared',
          data: { source: importPath },
        });
    }

    return {
      ImportDeclaration: checkImportSource,
      ExportNamedDeclaration: checkImportSource,
      ExportAllDeclaration: checkImportSource,
    };
  },
};

export default {
  rules: {
    'no-product-imports-in-shared': noProductImportsInSharedRule,
  },
};
